import sys
import math

def simple_median(values):
    """Compute median of a list"""
    sorted_vals = sorted(values)
    n = len(sorted_vals)
    if n % 2 == 1:
        return float(sorted_vals[n // 2])
    else:
        return (sorted_vals[n // 2 - 1] + sorted_vals[n // 2]) / 2.0

def test_rolling_median_logic():
    """Test rolling_median logic without importing numpy"""

    tests = [
        {
            'name': 'Basic valid mode',
            'a': [1, 2, 3, 4, 5],
            'window': 3,
            'mode': 'valid',
            'expected': [2., 3., 4.]
        },
        {
            'name': 'Window size 1',
            'a': [1, 2, 3, 4, 5],
            'window': 1,
            'mode': 'valid',
            'expected': [1., 2., 3., 4., 5.]
        },
        {
            'name': 'Window equals array length',
            'a': [1, 2, 3, 4, 5],
            'window': 5,
            'mode': 'valid',
            'expected': [3.]
        },
        {
            'name': 'Window larger than array',
            'a': [1, 2, 3],
            'window': 5,
            'mode': 'valid',
            'expected': []
        },
        {
            'name': 'Same mode',
            'a': [1, 2, 3, 4, 5],
            'window': 3,
            'mode': 'same',
            'expected_check': lambda result: (
                result[0] == 1.5 and  # median of [1, 2]
                result[2] == 3.0 and  # median of [1, 2, 3]
                result[4] == 4.5      # median of [4, 5]
            )
        },
        {
            'name': 'Even window size',
            'a': [1, 2, 3, 4, 5, 6],
            'window': 2,
            'mode': 'valid',
            'expected': [1.5, 2.5, 3.5, 4.5, 5.5]
        },
        {
            'name': 'With duplicates',
            'a': [1, 1, 1, 2, 2, 2],
            'window': 3,
            'mode': 'valid',
            'expected': [1., 1., 2., 2.]
        }
    ]

    passed = 0
    failed = 0

    for test in tests:
        a = test['a']
        window = test['window']
        mode = test['mode']

        # Compute rolling median manually
        n = len(a)

        if mode == 'valid':
            if window > n:
                result = []
            else:
                result = []
                for i in range(n - window + 1):
                    window_vals = a[i:i + window]
                    result.append(simple_median(window_vals))
        elif mode == 'same':
            result = []
            for i in range(n):
                start = i - window // 2
                end = start + window
                start = max(0, start)
                end = min(n, end)
                window_vals = a[start:end]
                result.append(simple_median(window_vals))

        # Check result
        if 'expected_check' in test:
            if test['expected_check'](result):
                print(f"✓ {test['name']}")
                passed += 1
            else:
                print(f"✗ {test['name']}: Check failed")
                print(f"  Result: {result}")
                failed += 1
        else:
            expected = test['expected']
            if len(result) == len(expected):
                all_match = all(
                    abs(r - e) < 1e-10 for r, e in zip(result, expected)
                )
                if all_match:
                    print(f"✓ {test['name']}")
                    passed += 1
                else:
                    print(f"✗ {test['name']}")
                    print(f"  Expected: {expected}")
                    print(f"  Got:      {result}")
                    failed += 1
            else:
                print(f"✗ {test['name']}")
                print(f"  Expected length {len(expected)}, got {len(result)}")
                print(f"  Expected: {expected}")
                print(f"  Got:      {result}")
                failed += 1

    print(f"\n{passed} passed, {failed} failed")
    return failed == 0

if __name__ == '__main__':
    success = test_rolling_median_logic()
    sys.exit(0 if success else 1)
